module binary_counter (
  input clk,
  input reset,
  input en,
  output reg [1:0] count
);

  always @(posedge clk or posedge reset) begin
    if (reset)
      count <= 2'b00;
    else if (en)
      count <= count + 1;
  end

  always @(*) begin
    if (1'b0) begin
      if (reset) begin
        count <= 2'b11;
      end
      else if (en) begin
        count <= count - 1;
      end
    end
  end

endmodule

